def normalise_per_dither(data, restore_median_level=True):
    """Additively normalise the data per dither.

    If `restore_median_level` is `False`, the median of the normalised data will be zero,
    otherwise it will be restored to the median level across the dithers.

    Including an estimate of the sky level in the autodark means that it is subtracted off the images before swarping.
    This was determined to be a good way to avoid introducing gradients in the background due to the variations in
    the pixel area across the FoV.
    """
    agg_dims = ["x", "y", "detector"]
    median_per_dither = data.median(dim=agg_dims, keep_attrs=True)
    data = data - median_per_dither
    if restore_median_level:
        median_level = median_per_dither.median(dim="dither")
        data = data + median_level
    return data


def prepare_group_data(data, group_for_obs_id, obs_id, short=False):
    group_obs_ids = group_for_obs_id[obs_id]
    group_data = data.sel(observation_id=data.observation_id.isin(group_obs_ids))
    short_dithers = np.array([str(x.values).endswith("-2") for x in group_data.dither])
    if short and not np.any(short_dithers):
        raise ValueError("No short dithers found.")
    select_dithers = short_dithers if short else ~short_dithers
    group_data = group_data.sel(dither=select_dithers)
    return group_data


def construct_skyflats(group_data):
    """Construct the skyflats for a given `obs_id`."""
    agg_dims = ["observation_id", "dither"]
    median = group_data.median(dim=agg_dims, keep_attrs=True)
    return median


def construct_skyflats_err(group_data, median):
    """Construct the error on the skyflats for a given `obs_id`."""
    abs_deviation = abs(group_data - median)
    agg_dims = ["observation_id", "dither"]
    mad = abs_deviation.median(dim=agg_dims, keep_attrs=True)
    n_ok = np.isfinite(data).sum(dim=agg_dims)
    err = mad * 1.4826 / np.sqrt(n_ok)
    return err

